  ARRAY['mailto:apply@brainjarskillsdev.co.za', 'mailto: apply@brainjarskillsdev.co.za', 'https://brainjarskillsdev.co.za/wp-content/uploads/2021/07/Application-form.pdf', 'https://brainjarskillsdev.co.za/wp-content/uploads/2021/09/Bursary-2021-Terms-Conditions.pdf']::text[],
